#include<bits/stdc++.h>
using namespace std;
struct edge
{
    long long to,val,nxt,cost;
}e[200010];
long long head[200010],tot=1,res;
long long n,m,s,t,d[200010],now[200010];
bool vis[200010];
void add1(long long u,long long v,long long w,long long c)
{
    e[++tot]=(edge){v,w,head[u],c};
    head[u]=tot;
}
void add(long long u,long long v,long long w,long long c)
{
    add1(u,v,w,-c);
    add1(v,u,0,c);
}
bool spfa()
{
    memset(d,0x3f,sizeof(d));
    long long tmp=d[0];
    queue<long long> q;
    q.push(s);
    d[s]=0;
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        vis[t]=false;
        for(int i=head[t];i;i=e[i].nxt)
        {
            int v=e[i].to,cost=e[i].cost;
            if(e[i].val&&d[v]>d[t]+cost)
            {
                d[v]=d[t]+cost;
                if(!vis[v])
                {
                    vis[v]=true;
                    q.push(v);
                }
            }
        }
    }
    return d[t]<tmp;
}
long long dfs(long long x,long long flow)
{
    if(x==t)
    {
        return flow;
    }
    vis[x]=true;
    long long sum=0;
    for(long long i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        long long v=e[i].to,val=e[i].val,cost=e[i].cost;
        if(!vis[v]&&d[v]==d[x]+cost&&val)
        {
            long long tmp=dfs(v,min(flow,val));
            e[i].val-=tmp;
            e[i^1].val+=tmp;
            sum+=tmp;
            res+=tmp*cost;
            flow-=tmp;
        }
    }
    vis[x]=false;
    return sum;
}
long long dinic()
{
    long long ans=0;
    while(spfa())
    {
        for(long long i=0;i<=t;i++)
        {
            now[i]=head[i];
        }
        ans+=dfs(s,INT_MAX);
    }
    return ans;
}
int a[5050][5050],idx[2][5050][5050];
int id(int x,int y)
{
    return (x-1)*m+y;
}
void print(int x,int i,int j)
{
    if(i<n)
    {
        if(e[idx[0][i][j]].val>0)
        {
            e[idx[0][i][j]].val--;
            printf("%d 0\n",x);
            print(x,i+1,j);
            return;
        }
    }
    if(j<m)
    {
        if(e[idx[1][i][j]].val>0)
        {
            e[idx[1][i][j]].val--;
            printf("%d 1\n",x);
            print(x,i,j+1);
            return;
        }
    }
}
int main()
{
    long long k;
    scanf("%lld%lld%lld",&k,&m,&n);
    s=1;
    t=n*m*2;
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<=m;j++)
        {
            scanf("%d",&a[i][j]);
            if(a[i][j]==0)
            {
                add(id(i,j)*2-1,id(i,j)*2,k,0);
            }
            else if(a[i][j]==2)
            {
                add(id(i,j)*2-1,id(i,j)*2,1,1);
                add(id(i,j)*2-1,id(i,j)*2,k-1,0);
            }
            if(a[i][j]!=1)
            {
                if(i<n&&a[i+1][j]!=1)
                {
                    add(id(i,j)*2,id(i+1,j)*2-1,k,0);
                    idx[0][i][j]=tot;
                }
                if(j<m&&a[i][j+1]!=1)
                {
                    add(id(i,j)*2,id(i,j+1)*2-1,k,0);
                    idx[1][i][j]=tot;
                }
            }
        }
    }
    dinic();
    for(int i=1;i<=k;i++)
    {
        print(i,1,1);
    }
    return 0;
}
